from __future__ import annotations

import base64
import gzip
import subprocess
from pathlib import Path

PATCH = """"""

patch = gzip.decompress(base64.b64decode(PATCH))
patch_path = Path(".goose-mainwindow.patch")
patch_path.write_bytes(patch)
try:
    subprocess.run(["git", "apply", "--whitespace=nowarn", str(patch_path)], check=True)
finally:
    patch_path.unlink(missing_ok=True)

print("Applied GOOSE Subscriber navigation, workspace, lifecycle, and UI-flush patch.")
